from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetCurrentSceneNode(BaseNode):
    name = "Prism: Get Current Scene"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_output("file_path", "string")
        self.add_output("entity", "dict")
        self.add_output("department", "string")
        self.add_output("task", "string")
        self.add_output("version", "string")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        if core is None:
            self.log_error("No PrismCore provided.")
            return {'file_path':'','entity':{},'department':'','task':'','version':''}
        try:
            fpath = ''
            for attr in ('getCurrentFileName', 'getCurrentScenefile'):
                if hasattr(core, attr):
                    fpath = str(getattr(core, attr)() or '')
                    if fpath: break
            data = {}
            if fpath:
                for attr in ('getScenefileData', 'getDataFromScenefile'):
                    if hasattr(core, attr):
                        try:
                            data = getattr(core, attr)(fpath) or {}
                            break
                        except Exception:
                            data = {}
            entity = {}
            if isinstance(data, dict):
                if data.get('type') in ('asset','shot'):
                    entity = {k:v for k,v in data.items() if k in ('type','asset_path','sequence','shot')}
                else:
                    entity = data.get('entity') or {}
            dept = str((data or {}).get('department','') or '')
            task = str((data or {}).get('task','') or '')
            ver  = str((data or {}).get('version','') or '')
            self.log_info(f"Current scene: {fpath}")
            return {'file_path': fpath, 'entity': entity, 'department': dept, 'task': task, 'version': ver}
        except Exception as e:
            self.log_error(f"getCurrentScene failed: {e}")
            return {'file_path':'','entity':{},'department':'','task':'','version':''}

def register_node():
    return PrismGetCurrentSceneNode
